const assert = require('assert');

// Create a direct implementation of characterfrequencytokenizer for testing
function characterfrequencytokenizer(s) {
  var letters = 'abcdefghijklmnopqrstuvwxyz'.split('');
  return letters.map(function(x) { return s.toLowerCase().split(x).length - 1; });
}

// Test empty string
function testEmptyString() {
  const result = characterfrequencytokenizer('');
  assert.strictEqual(result.length, 26);
  assert.strictEqual(result.reduce((a, b) => a + b, 0), 0);
  assert.deepStrictEqual(result, Array(26).fill(0));
}

// Test single character
function testSingleChar() {
  let result = characterfrequencytokenizer('a');
  assert.strictEqual(result.length, 26);
  assert.strictEqual(result.reduce((a, b) => a + b, 0), 1);
  assert.strictEqual(result[0], 1); // 'a' is at index 0

  result = characterfrequencytokenizer('z');
  assert.strictEqual(result.length, 26);
  assert.strictEqual(result.reduce((a, b) => a + b, 0), 1);
  assert.strictEqual(result[25], 1); // 'z' is at index 25
}

// Test mixed case
function testMixedCase() {
  let result = characterfrequencytokenizer('Aa');
  assert.strictEqual(result.length, 26);
  assert.strictEqual(result.reduce((a, b) => a + b, 0), 2);
  assert.strictEqual(result[0], 2); // 'a' and 'A' count as 'a'

  result = characterfrequencytokenizer('aAbBcC');
  assert.strictEqual(result.length, 26);
  assert.strictEqual(result.reduce((a, b) => a + b, 0), 6);
  assert.strictEqual(result[0], 2); // 'a' and 'A' count as 'a'
  assert.strictEqual(result[1], 2); // 'b' and 'B' count as 'b'
  assert.strictEqual(result[2], 2); // 'c' and 'C' count as 'c'
}

// Test repeated characters
function testRepeatedChars() {
  let result = characterfrequencytokenizer('aaa');
  assert.strictEqual(result.length, 26);
  assert.strictEqual(result.reduce((a, b) => a + b, 0), 3);
  assert.strictEqual(result[0], 3); // 'a' appears 3 times

  result = characterfrequencytokenizer('abcaba');
  assert.strictEqual(result.length, 26);
  assert.strictEqual(result.reduce((a, b) => a + b, 0), 6);
  assert.strictEqual(result[0], 3); // 'a' appears 3 times
  assert.strictEqual(result[1], 2); // 'b' appears 2 times
  assert.strictEqual(result[2], 1); // 'c' appears 1 time
}

// Test non-alpha characters
function testNonAlphaChars() {
  const result = characterfrequencytokenizer('a1b@c#');
  assert.strictEqual(result.length, 26);
  assert.strictEqual(result.reduce((a, b) => a + b, 0), 3); // Only counts a, b, c
  assert.strictEqual(result[0], 1);
  assert.strictEqual(result[1], 1);
  assert.strictEqual(result[2], 1);
}

