  assert.strictEqual(levenshtein.distance("abc", ""), 3);

  // Test simple cases
  assert.strictEqual(levenshtein.distance("a", "b"), 1);
  assert.strictEqual(levenshtein.distance("ab", "cd"), 2);
  assert.strictEqual(levenshtein.distance("abc", "abd"), 1);

  // Test insertions and deletions
  assert.strictEqual(levenshtein.distance("ab", "abc"), 1);
  assert.strictEqual(levenshtein.distance("abc", "ab"), 1);
  assert.strictEqual(levenshtein.distance("abcd", "ab"), 2);

  // Test substitutions
  assert.strictEqual(levenshtein.distance("ab", "cd"), 2);
  assert.strictEqual(levenshtein.distance("abc", "def"), 3);

  // Test with unicode characters
  assert.strictEqual(levenshtein.distance(input_shanghai, input_shanghai_city), 1);

  // Test with mixed operations (insertions, deletions, substitutions)
  assert.strictEqual(levenshtein.distance("kitten", "sitting"), 3);
  assert.strictEqual(levenshtein.distance("intention", "execution"), 5);

  // Test case sensitivity
  assert.strictEqual(levenshtein.distance("ABC", "abc"), 3);
  assert.strictEqual(levenshtein.distance("ABC", "ABC"), 0);

