const assert = require('assert');
const SorensenDice = require('./translated.js').SorensenDice;
const {input_shanghai, input_shanghai_city} = require('./tracer_skip.js');

// Helper function for testing
function assertAlmostEqual(actual, expected, places = 2) {
    const factor = Math.pow(10, places);
    const actualRounded = Math.round(actual * factor) / factor;
    const expectedRounded = Math.round(expected * factor) / factor;
    assert.strictEqual(actualRounded, expectedRounded);
}

// Test class for SorensenDice similarity
class TestSorensenDiceSimilarity {
    constructor() {
        this.sorensen = SorensenDice(2); // Create instance with shingle size 2
    }

    test_empty_strings() {
        // Test with empty strings
        assert.strictEqual(this.sorensen.similarity("", ""), 1.0);
        console.log("✓ test_empty_strings passed");
    }

    test_null_arguments() {
        // Test with null arguments
        let caught = false;
        try {
            this.sorensen.similarity(null, "test");
        } catch (e) {
            assert(e instanceof TypeError);
            caught = true;
        }
        assert(caught, "Should throw TypeError for null first argument");

        caught = false;
        try {
            this.sorensen.similarity("test", null);
        } catch (e) {
            assert(e instanceof TypeError);
            caught = true;
        }
        assert(caught, "Should throw TypeError for null second argument");

        caught = false;
        try {
            this.sorensen.similarity(null, null);
        } catch (e) {
            assert(e instanceof TypeError);
            caught = true;
        }
        assert(caught, "Should throw TypeError for both null arguments");
        console.log("✓ test_null_arguments passed");
    }

    test_identical_strings() {
        // Test with identical strings
        assert.strictEqual(this.sorensen.similarity("test", "test"), 1.0);
        assert.strictEqual(this.sorensen.similarity(input_shanghai, input_shanghai), 1.0);
        console.log("✓ test_identical_strings passed");
    }

    test_different_strings() {
        // Test with different strings
        // The actual similarity value depends on the profiles and intersection calculation
        const similarity = this.sorensen.similarity(input_shanghai, input_shanghai_city);
        assertAlmostEqual(similarity, 0.67, 2);
        console.log("✓ test_different_strings passed");
    }

    test_disjoint_strings() {
        // Test with completely different strings that have no common shingles
        assert.strictEqual(this.sorensen.similarity("abc", "def"), 0.0);
        console.log("✓ test_disjoint_strings passed");
    }

    test_overlapping_strings() {
        // Test with strings that have some overlapping shingles
        const similarity = this.sorensen.similarity("hello", "helloworld");
        assert(0 <= similarity && similarity <= 1, "Similarity should be between 0 and 1");
        console.log("✓ test_overlapping_strings passed");
    }

    test_corner_cases() {
        // Test corner cases with special characters
        assert.strictEqual(this.sorensen.similarity("  ", "  "), 1.0);
        const similarity = this.sorensen.similarity("a b", "a  b");
        assert(0 <= similarity && similarity <= 1, "Similarity should be between 0 and 1 (inclusive)");
        console.log("✓ test_corner_cases passed");
    }

    test_profile_handling() {
        // This test specifically tests the profile key handling which is crucial
        // for the intersection calculation and is the likely source of problems
        // in the JavaScript implementation
        const s1 = "abcd";
        const s2 = "abce";

        // Get profiles manually
        const profile1 = this.sorensen.get_profile(s1);
        const profile2 = this.sorensen.get_profile(s2);

        // Calculate union manually
        const union = new Set();
        for (const k in profile1) {
            if (profile1.hasOwnProperty(k)) {
                union.add(k);
            }
        }
        for (const k in profile2) {
            if (profile2.hasOwnProperty(k)) {
                union.add(k);
            }
        }

        // Calculate intersection manually
        const intersection = Object.keys(profile1).length + Object.keys(profile2).length - union.size;

        // Calculate similarity
        const expected = 2.0 * intersection / (Object.keys(profile1).length + Object.keys(profile2).length);
        const actual = this.sorensen.similarity(s1, s2);

        assert.strictEqual(actual, expected);
        console.log("✓ test_profile_handling passed");
    }

    run_all_tests() {
        this.test_empty_strings();
        this.test_null_arguments();
        this.test_identical_strings();
        this.test_different_strings();
        this.test_disjoint_strings();
        this.test_overlapping_strings();
        this.test_corner_cases();
        this.test_profile_handling();
        console.log("All tests passed!");
    }
}

// Run the tests
const tester = new TestSorensenDiceSimilarity();
tester.run_all_tests();
